// CustomerService - Validar respuestas de Product API
@Service
public class CustomerService {

    @Autowired
    private WebClient productWebClient;

    public Customer create(Customer customer) {
        // Validar que productos existen
        if (customer.getProductIds() != null) {
            for (Long productId : customer.getProductIds()) {
                validateProductExists(productId);
            }
        }

        return customerRepository.save(customer);
    }

    private void validateProductExists(Long productId) {
        try {
            Product product = productWebClient.get()
                .uri("/product/{id}", productId)
                .retrieve()
                .onStatus(
                    status -> status.is4xxClientError(),
                    clientResponse -> {
                        if (clientResponse.statusCode().equals(HttpStatus.NOT_FOUND)) {
                            return Mono.error(new NotFoundException(
                                "Product with ID " + productId + " not found"
                            ));
                        }
                        return Mono.error(new IllegalArgumentException(
                            "Invalid product ID: " + productId
                        ));
                    }
                )
                .onStatus(
                    status -> status.is5xxServerError(),
                    clientResponse -> {
                        log.error("Product service error: {}", 
                                 clientResponse.statusCode());
                        return Mono.error(new ServiceUnavailableException(
                            "Product service is currently unavailable"
                        ));
                    }
                )
                .bodyToMono(Product.class)
                .block();

        } catch (WebClientException e) {
            log.error("Error calling Product service", e);
            throw new ServiceUnavailableException(
                "Unable to validate product: " + e.getMessage()
            );
        }
    }
}

// ServiceUnavailableException.java
public class ServiceUnavailableException extends BusinessException {
    public ServiceUnavailableException(String message) {
        super(message);
    }
}

// GlobalExceptionHandler - Handler para service unavailable
@ExceptionHandler(ServiceUnavailableException.class)
public ResponseEntity<ErrorResponse> handleServiceUnavailable(
        ServiceUnavailableException ex, WebRequest request) {

    log.error("Service unavailable: {}", ex.getMessage());

    ErrorResponse error = new ErrorResponse(
        HttpStatus.SERVICE_UNAVAILABLE.value(),
        "Service Unavailable",
        ex.getMessage(),
        request.getDescription(false).replace("uri=", "")
    );

    return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE)
        .body(error);
}

// WebClientConfig - Con timeout
@Bean
public WebClient productWebClient(WebClient.Builder builder) {
    return builder
        .baseUrl("http://product-service/api/v1")
        .defaultHeader(HttpHeaders.CONTENT_TYPE, 
                      MediaType.APPLICATION_JSON_VALUE)
        .build();
}
